const input = $input.first().json;
const msgText = (input.message && input.message.text) ? input.message.text : (input.text || '');

const CONSUMER_KEY    = $vars['ETRADE_CONSUMER_KEY'];
const CONSUMER_SECRET = $vars['ETRADE_CONSUMER_SECRET'];
const N8N_API_KEY     = $vars['N8N_API_KEY'];
const N8N_BASE        = 'https://ashes2echoes.app.n8n.cloud';
const crypto = require('crypto');
function pct(s) { return encodeURIComponent(String(s)); }

const verifier = msgText.trim().split(/\s+/)[0];
if (!verifier || verifier.length < 4 || verifier.length > 10) {
  return [{ json: { status: 'IGNORED', msg: msgText, reason: 'Not a verifier code' } }];
}

// Read request tokens FRESH via API (not $vars which are cached)
async function getVar(key) {
  const vars = await this.helpers.httpRequest({method:'GET',url:N8N_BASE+'/api/v1/variables',headers:{'X-N8N-API-KEY':N8N_API_KEY}});
  const v = (vars.data||[]).find(x=>x.key===key);
  return v ? v.value : '';
}

const requestToken       = await getVar.call(this, 'ETRADE_REQUEST_TOKEN');
const requestTokenSecret = await getVar.call(this, 'ETRADE_REQUEST_TOKEN_SECRET');

if (!requestToken || requestToken === 'pending' || requestToken === 'used') {
  return [{ json: { status: 'ERROR', error: 'No valid request token. Run TOKEN KEEPER first.', verifier, storedToken: requestToken } }];
}

const ts    = String(Math.floor(Date.now()/1000));
const nonce = Math.random().toString(36).substring(2,14);
const ACC_URL = 'https://api.etrade.com/oauth/access_token';
const params = {
  oauth_consumer_key:CONSUMER_KEY, oauth_nonce:nonce,
  oauth_signature_method:'HMAC-SHA1', oauth_timestamp:ts,
  oauth_token:requestToken, oauth_verifier:verifier, oauth_version:'1.0'
};
const sortedStr = Object.keys(params).sort().map(k=>pct(k)+'='+pct(params[k])).join('&');
const baseStr = 'GET&'+pct(ACC_URL)+'&'+pct(sortedStr);
const sigKey = pct(CONSUMER_SECRET)+'&'+pct(requestTokenSecret);
const sig = crypto.createHmac('sha1',sigKey).update(baseStr).digest('base64');
params['oauth_signature'] = sig;
const authHeader = 'OAuth realm="",' + Object.keys(params).filter(k=>k.startsWith('oauth_')).sort().map(k=>k+'="'+pct(params[k])+'"').join(',');

let newToken, newSecret;
try {
  const resp = await this.helpers.httpRequest({method:'GET',url:ACC_URL,headers:{'Authorization':authHeader}});
  const body = typeof resp==='string' ? resp : JSON.stringify(resp);
  const parsed = {};
  body.split('&').forEach(p=>{const[k,v]=p.split('=');if(k)parsed[k]=decodeURIComponent(v||'');});
  newToken  = parsed['oauth_token']||'';
  newSecret = parsed['oauth_token_secret']||'';
} catch(e) {
  return [{json:{status:'EXCHANGE_ERROR',error:e.message,verifier}}];
}

if (!newToken) return [{json:{status:'NO_TOKEN',raw:'exchange returned empty'}}];

async function updateVar(key, value) {
  const vars = await this.helpers.httpRequest({method:'GET',url:N8N_BASE+'/api/v1/variables',headers:{'X-N8N-API-KEY':N8N_API_KEY}});
  const varObj = (vars.data||[]).find(v=>v.key===key);
  if(!varObj) return;
  try { await this.helpers.httpRequest({method:'PATCH',url:N8N_BASE+'/api/v1/variables/'+varObj.id,headers:{'X-N8N-API-KEY':N8N_API_KEY,'Content-Type':'application/json'},body:JSON.stringify({key,value})}); } catch(e) {}
}

await updateVar.call(this,'ETRADE_ACCESS_TOKEN',newToken);
await updateVar.call(this,'ETRADE_ACCESS_TOKEN_SECRET',newSecret);
await updateVar.call(this,'ETRADE_REQUEST_TOKEN','used');
await updateVar.call(this,'ETRADE_REQUEST_TOKEN_SECRET','used');

return [{json:{status:'SUCCESS',new_token_preview:newToken.substring(0,15)+'...',timestamp:new Date().toISOString()}}];

